/* ─── Logo component ─────────────────────────────── */
function LogoMark({ logoKey, logoBgColor, accentColor }) {
  return (
    <div
      style={{
        width: 52,
        height: 52,
        borderRadius: 10,
        background: logoBgColor,
        border: `1.5px solid ${accentColor}30`,
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        flexShrink: 0,
        overflow: "hidden",
        padding: 4,
      }}
      aria-hidden="true"
    >
      <img
        src={LOGOS[logoKey]}
        alt=""
        style={{
          width: "100%",
          height: "100%",
          objectFit: "contain",
          display: "block",
        }}
      />
    </div>
  );
}

/* ─── Card ────────────────────────────────────────── */
function ScholarshipCard({ card, index }) {
  const {
    badge, logoKey, logoBgColor,
    cardBg, cardBorder, cardBorderHover,
    accentColor, accentLight, btnBorder, btnHoverBg,
    title, org, location, description, deadline, featured, url,
  } = card;
  const b = BADGE[badge];

  const handleClick = () => window.open(url, "_blank", "noopener,noreferrer");

  return (
    <motion.article
      className={`ks-sc-card${featured ? " featured" : ""}`}
      style={{
        "--card-bg": cardBg,
        "--card-border": cardBorder,
        "--card-border-hover": cardBorderHover,
        "--accent": accentColor,
        "--btn-border": btnBorder,
        "--btn-hover-bg": btnHoverBg,
        "--featured-top": accentColor,
      }}
      initial={{ opacity: 0, y: 22 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.48, delay: 0.07 + index * 0.09, ease: [0.22, 1, 0.36, 1] }}
      whileHover={{ y: -5, transition: { duration: 0.2, ease: [0.22, 1, 0.36, 1] } }}
      onClick={handleClick}
      onKeyDown={(e) => e.key === "Enter" && handleClick()}
      tabIndex={0}
      role="button"
      aria-label={`${title} — visit official site`}
    >
      <div className="ks-sc-top">
        <span className="ks-sc-badge" style={{ background: b.bg, color: b.color }}>
          <span className="ks-sc-badge-dot" style={{ background: b.dot }} />
          {badge}
        </span>
        <LogoMark logoKey={logoKey} logoBgColor={logoBgColor} accentColor={accentColor} />
      </div>

      <div className="ks-sc-body">
        <h3 className="ks-sc-title-text">{title}</h3>
        <p className="ks-sc-org">{org}</p>
        {location && (
          <p className="ks-sc-location">
            <MapPin size={11} strokeWidth={2} />{location}
          </p>
        )}
      </div>

      <p className="ks-sc-desc">{description}</p>

      <div className="ks-sc-deadline" style={{ color: accentColor }}>
        <Calendar size={12} strokeWidth={2} />
        <span>Deadline: <strong>{deadline}</strong></span>
      </div>

      <div className="ks-sc-btn" aria-hidden="true">
        <span>Visit Official Site</span>
        <ExternalLink size={12} strokeWidth={2.5} />
      </div>
    </motion.article>
  );
}

/* ─── Dots ────────────────────────────────────────── */
function Dots({ total, active, onChange }) {
  return (
    <div className="ks-sc-dots" role="tablist" aria-label="Scholarship pages">
      {Array.from({ length: total }).map((_, i) => (
        <button
          key={i} role="tab"
          aria-selected={i === active}
          aria-label={`Page ${i + 1}`}
          onClick={() => onChange(i)}
          className={`ks-sc-dot${i === active ? " active" : ""}`}
        />
      ))}
    </div>
  );
}

